def temperature_table(celsius_temps):
    result = []
    for c in celsius_temps:
        f = round(c * 9 / 5 + 32, 2)
        k = round(c + 273.15, 2)
        if c <= 0:
            condition = "Freezing"
        elif c <= 15:
            condition = "Cold"
        elif c <= 25:
            condition = "Mild"
        elif c <= 35:
            condition = "Hot"
        else:
            condition = "Extreme"
        result.append({"celsius": c, "fahrenheit": f, "kelvin": k, "condition": condition})
    return result
